package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.support.DefaultAsyncProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * FIX Producer for sending FIX protocol messages
 */
public class FixProducer extends DefaultAsyncProducer {

    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);
    private final FixEndpoint endpoint;

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
        this.endpoint = endpoint;
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            String messageBody = exchange.getIn().getBody(String.class);
            String messageType = exchange.getIn().getHeader(FixConstants.FIX_MESSAGE_TYPE, String.class);
            String senderCompID = exchange.getIn().getHeader(FixConstants.FIX_SENDER_COMP_ID, String.class);
            String targetCompID = exchange.getIn().getHeader(FixConstants.FIX_TARGET_COMP_ID, String.class);

            LOG.debug("Sending FIX message - Type: {}, Sender: {}, Target: {}", messageType, senderCompID, targetCompID);

            // In a real implementation, this would send the message through the FIX engine
            // For now, we just log the message
            processFIXMessage(messageBody, messageType, senderCompID, targetCompID);

            callback.done(true);
            return true;
        } catch (Exception e) {
            exchange.setException(e);
            callback.done(true);
            return true;
        }
    }

    /**
     * Process a FIX message for sending
     */
    private void processFIXMessage(String messageBody, String messageType, String senderCompID, String targetCompID) {
        LOG.info("FIX message processed: {} bytes", messageBody != null ? messageBody.length() : 0);
        // Implementation would send message through FIX engine
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        LOG.info("FIX Producer starting");
    }

    @Override
    protected void doStop() throws Exception {
        super.doStop();
        LOG.info("FIX Producer stopping");
    }
}

