import org.apache.camel.support.DefaultConsumer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * FIX Consumer for receiving FIX protocol messages
 */
public class FixConsumer extends DefaultConsumer {

    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);
    private final FixEndpoint endpoint;

    public FixConsumer(FixEndpoint endpoint, Processor processor) {
        super(endpoint, processor);
        this.endpoint = endpoint;
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        LOG.info("FIX Consumer starting for session: {}", endpoint.getConfiguration().getSenderCompID());
        // FIX acceptor session lifecycle management would be handled here
    }

    @Override
    protected void doStop() throws Exception {
        super.doStop();
        LOG.info("FIX Consumer stopping for session: {}", endpoint.getConfiguration().getSenderCompID());
        // FIX acceptor session cleanup would be handled here
    }

    /**
     * Process a FIX message from the protocol engine
     */
    public void processFixMessage(String messageType, String senderCompID, String targetCompID, String messageBody) throws Exception {
        Exchange exchange = createExchange(false);
        exchange.getIn().setBody(messageBody);
        exchange.getIn().setHeader(FixConstants.FIX_MESSAGE_TYPE, messageType);
        exchange.getIn().setHeader(FixConstants.FIX_SENDER_COMP_ID, senderCompID);
        exchange.getIn().setHeader(FixConstants.FIX_TARGET_COMP_ID, targetCompID);

        try {
            getProcessor().process(exchange);
        } finally {
            releaseExchange(exchange, false);
        }
    }
}

