public class FixProducer extends DefaultAsyncProducer {
    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);
    private final FixEndpoint endpoint;

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
        this.endpoint = endpoint;
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            String messageBody = exchange.getIn().getBody(String.class);
            String messageType = exchange.getIn().getHeader(
                FixConstants.FIX_MESSAGE_TYPE, String.class);
            String senderCompID = exchange.getIn().getHeader(
                FixConstants.FIX_SENDER_COMP_ID, String.class);
            String targetCompID = exchange.getIn().getHeader(
                FixConstants.FIX_TARGET_COMP_ID, String.class);

            LOG.debug("Sending FIX message - Type: {}, Sender: {}, Target: {}",
                     messageType, senderCompID, targetCompID);

            processFIXMessage(messageBody, messageType, senderCompID, targetCompID);
            callback.done(true);
            return true;
        } catch (Exception e) {
            exchange.setException(e);
            callback.done(true);
            return true;
        }
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        LOG.info("FIX Producer starting");
    }

    @Override
    protected void doStop() throws Exception {
        super.doStop();
        LOG.info("FIX Producer stopping");
    }
}
